import { motion, AnimatePresence } from "framer-motion";
import { Search, ChevronDown, Plus, Pencil, Trash2 } from "lucide-react";
import { linkHomeDesign as design } from "../../../design/linkHomeDesign";

const LinkShow = ({
  links,
  search,
  setSearch,
  sort,
  setSort,
  sortOptions,
  dropdownOpen,
  setDropdownOpen,
  dropdownRef,
  setView,
    handleDelete,
  handleEdit,
}) => {
  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        <AnimatePresence mode="wait">
          <motion.div
            key="home"
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 30 }}
            transition={{ duration: 0.3 }}
            className="space-y-6"
          >
            <div className={design.navbar}>
              <div className={design.searchWrapper}>
                <Search size={16} />
                <input
                  type="text"
                  placeholder="Search link..."
                  value={search}
                  onChange={(e) =>
                    setSearch(e.target.value)
                  }
                  className={design.searchInput}
                />
              </div>

              <div className={design.rightControls}>
                <div
                  className={design.dropdownWrapper}
                  ref={dropdownRef}
                >
                  <button
                    onClick={() =>
                      setDropdownOpen(!dropdownOpen)
                    }
                    className={design.dropdownButton}
                  >
                    {
                      sortOptions.find(
                        (o) => o.value === sort
                      )?.label
                    }
                    <ChevronDown size={16} />
                  </button>

                  <AnimatePresence>
                    {dropdownOpen && (
                      <motion.div
                        initial={{ opacity: 0, y: -6 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0 }}
                        className={design.dropdownMenu}
                      >
                        {sortOptions.map((option) => (
                          <div
                            key={option.value}
                            onClick={() => {
                              setSort(option.value);
                              setDropdownOpen(false);
                            }}
                            className={`${design.dropdownItem} ${
                              sort === option.value
                                ? design.dropdownActive
                                : ""
                            }`}
                          >
                            {option.label}
                          </div>
                        ))}
                      </motion.div>
                    )}
                  </AnimatePresence>
                </div>

                <button
                  onClick={() => setView("add")}
                  className={design.addButton}
                >
                  <Plus size={16} />
                  Add Link
                </button>
              </div>
            </div>

            {links.length > 0 ? (
              <div className={design.table}>
                {links.map((link, index) => (
                  <div
                    key={link._id}
                    className={design.row}
                  >
                    <div>{index + 1}</div>
                    <div>{link.name}</div>
                    <div>
                      {link.isActive
                        ? "Active"
                        : "Inactive"}
                    </div>
                    <div className="flex justify-end gap-4">
  <Pencil
    size={16}
    className="cursor-pointer"
    onClick={() => handleEdit(link)}
  />

  <Trash2
    size={16}
    className="text-red-500 cursor-pointer"
    onClick={() => handleDelete(link._id)}
  />
</div>
                  </div>
                ))}
              </div>
            ) : (
              <div className={design.emptyState}>
                No parent links found.
              </div>
            )}
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  );
};

export default LinkShow;
